   304	    private int readDataFromCachedFile(RetryingPooledBookkeeperClient bookKeeperClient, String remotePath, long offset, int readLength) throws IOException, TException
   305	    {
   306	      FileChannel fc = null;
   307	      int nread = 0;
   308	      String filename = CacheUtil.getLocalPath(remotePath, conf);
   309	
   310	      try {
   311	        fc = new FileInputStream(filename).getChannel();
   312	        int maxCount = CacheConfig.getDataTransferBufferSize(conf);
   313	        int lengthRemaining = readLength;
   314	        long position = offset;
   315	
   316	        // This situation should not arise as ActualReadLength cannot be greater than the file size.
   317	        // This seems to case of corrupted file. We should invalidate the file in this case.
   318	        if (fc.size() < readLength) {
   319	          log.error(String.format("File size is smaller than requested read. Invalidating corrupted cached file %s", remotePath));
   320	          bookKeeperClient.invalidateFileMetadata(remotePath);
   321	          throw new IOException("File size is smaller than requested read");
   322	        }
   323	
   324	        while (nread < readLength) {
   325	          if (maxCount > lengthRemaining) {
   326	            maxCount = lengthRemaining;
   327	          }
   328	          nread += fc.transferTo(position + nread, maxCount, localDataTransferClient);
   329	          lengthRemaining = readLength - nread;
   330	        }
   331	      }
   332	      catch (FileNotFoundException ex) {
   333	        log.error(String.format("Could not create file channel for %s. Invalidating missing remote file %s", filename, remotePath));
