   112	    CacheConfig.setCacheDataEnabled(conf, false);
   113	
   114	    this.metrics = metricsRegistry;
   115	    this.bookKeeperMetrics = new BookKeeperMetrics(conf, metrics);
   116	    registerMetrics(conf);
